{
  "name": "turbotrack",
  "version": "1.0.0",
  "description": "",
  "main": "server.js",
  "scripts": {
    "start": "node server.js"
  },
  "keywords": [],
  "author": "",
  "license": "ISC",
  "dependencies": {
    "express": "^4.18.2"
  }
}

require('dotenv').config();
const express = require('express');
const app = express();
const port = process.env.PORT;

app.use(express.static('public'));

app.get('/', (req, res) => {
  res.sendFile(__dirname + '/public/index.html');
});

app.get('/api/health', (req, res) => {
  res.status(200).send({ message: 'Server is healthy' });
});

app.listen(port, () => {
  console.log(`Server started on port ${port}`);
});

:root {
  --primary-color: #0a0a0f;
  --accent-color: #ff00ff;
  --background-color: #1a1a2e;
  --text-color: #ffffff;
  --font-family: 'Google Sans', sans-serif;
}

body {
  font-family: var(--font-family);
  background-color: var(--background-color);
  color: var(--text-color);
  margin: 0;
  padding: 0;
}

header {
  background-color: var(--primary-color);
  color: var(--text-color);
  padding: 1rem;
  text-align: center;
}

main {
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 2rem;
}

section {
  background-color: var(--background-color);
  padding: 1rem;
  border-radius: 16px;
  box-shadow: 0 0 10px rgba(0, 0, 0, 0.2);
  margin-bottom: 1rem;
}

h1, h2 {
  color: var(--accent-color);
  margin-bottom: 0.5rem;
}

button {
  background-color: var(--accent-color);
  color: var(--text-color);
  border: none;
  padding: 0.5rem 1rem;
  border-radius: 8px;
  cursor: pointer;
}

button:hover {
  transform: scale(1.05);
  box-shadow: 0 0 10px rgba(0, 0, 0, 0.2);
}

button:active {
  transform: scale(0.96);
}

ul {
  list-style: none;
  padding: 0;
  margin: 0;
}

li {
  margin-bottom: 0.5rem;
}

#hero {
  background-image: linear-gradient(to bottom, #ff00ff, #00ffff);
  background-size: 100% 300px;
  background-position: 0% 100%;
  height: 100vh;
  display: flex;
  justify-content: center;
  align-items: center;
  color: var(--text-color);
}

#start-button {
  font-size: 1.5rem;
  padding: 0.5rem 1rem;
}

document.addEventListener('DOMContentLoaded', () => {
  const startButton = document.getElementById('start-button');

  startButton.addEventListener('click', () => {
    // Add game logic here
    console.log('Start button clicked');
  });
});

:root {
  --primary-color: #0a0a0f;
  --accent-color: #ff00ff;
  --background-color: #1a1a2e;
  --text-color: #ffffff;
  --font-family: 'DM Sans', sans-serif;
  --scanline-color: #6600ff;
  --scanline-opacity: 0.2;
  --hud-color: #33ccff;
  --hud-background-color: rgba(0, 0, 0, 0.5);
}

body {
  font-family: var(--font-family);
  background-color: var(--background-color);
  color: var(--text-color);
  margin: 0;
  padding: 0;
  background-image: linear-gradient(180deg, #2c2c3f, #1a1a2e);
}

header {
  background-color: var(--primary-color);
  color: var(--text-color);
  padding: 1rem;
  text-align: center;
  box-shadow: 0px 2px 10px rgba(0, 0, 0, 0.2);
}

main {
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 2rem;
}

section {
  background-color: var(--background-color);
  padding: 1rem;
  border-radius: 10px;
  box-shadow: 0px 2px 10px rgba(0, 0, 0, 0.2);
}

h1 {
  font-size: 48px;
  font-weight: 700;
  color: var(--accent-color);
  text-transform: uppercase;
  margin-bottom: 10px;
}

h2 {
  font-size: 24px;
  font-weight: 400;
  color: var(--text-color);
  margin-bottom: 20px;
}

.scanline {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 20px;
  background-image: linear-gradient(to right, var(--scanline-color) 50%, transparent 50%);
  background-size: 20px 20px;
  opacity: var(--scanline-opacity);
  animation: scanline 10s linear infinite;
}

@keyframes scanline {
  0% {
    transform: translateY(0);
  }
  100% {
    transform: translateY(-100%);
  }
}

.hud {
  position: fixed;
  top: 10px;
  left: 10px;
  background-color: var(--hud-background-color);
  padding: 10px;
  border-radius: 10px;
  box-shadow: 0px 2px 10px rgba(0, 0, 0, 0.2);
}

.hud .hud-content {
  color: var(--hud-color);
  font-size: 18px;
}

button {
  background-color: var(--accent-color);
  color: var(--text-color);
  border: none;
  padding: 10px 20px;
  font-size: 18px;
  cursor: pointer;
  border-radius: 10px;
  box-shadow: 0px 2px 10px rgba(0, 0, 0, 0.2);
}

button:hover {
  background-color: #ff33cc;
}

